const incoming = $input.first().json;
const headers = incoming.headers ?? {};
const body = incoming.body ?? incoming;
const apiKey = headers['x-api-key'] ?? headers['X-Api-Key'] ?? headers['X-API-KEY'];
const secret = $env.N8N_WEBHOOK_SECRET;

if (!secret) {
  throw new Error('N8N_WEBHOOK_SECRET is not configured');
}

if (apiKey !== secret) {
  throw new Error('Unauthorized: invalid x-api-key');
}

if (!body.examResultId || !body.score || !body.passingStatus || !Array.isArray(body.weakAreas)) {
  throw new Error('Invalid payload: examResultId, score, passingStatus, and weakAreas are required');
}

const weakAreas = body.weakAreas.slice(0, 5);
const weakAreaMap = Object.fromEntries(
  weakAreas.map((item) => [`${item.category}::${item.subCategory}::${item.topicTag}`, true]),
);

const prompt = [
  'Anda adalah mesin rekomendasi belajar CPNS.',
  'Gunakan hanya weakAreas yang diberikan oleh backend.',
  'Jangan mengarang topicTag baru.',
  'Jangan bertindak seperti chatbot.',
  'Jangan menjanjikan pasti lulus.',
  'Keluarkan JSON valid saja tanpa markdown fence.',
  '',
  'Format output wajib:',
  JSON.stringify({
    summary: 'string',
    overallAssessment: 'string',
    recommendations: [
      {
        priority: 1,
        priorityLevel: 'HIGH',
        category: 'TWK',
        subCategory: 'Tata Negara',
        topicTag: 'Hak dan Kewajiban Warga Negara',
        reason: 'string',
        suggestedFocus: ['string']
      }
    ],
    nextTryoutStrategy: 'string'
  }, null, 2),
  '',
  'Input JSON dari backend:',
  JSON.stringify(body, null, 2),
].join('\n');

const model = $env.OPENAI_MODEL || 'gpt-4.1-mini';
const llmRequest = {
  model,
  temperature: 0.2,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'Anda menghasilkan rekomendasi belajar CPNS berbentuk JSON valid.'
    },
    {
      role: 'user',
      content: prompt
    }
  ]
};

return [{
  json: {
    body,
    weakAreaMap,
    weakAreas,
    llmRequest
  }
}];

const llmResponse = $input.first().json;
const context = $('Validate Payload And Build Prompt').first().json;
const weakSet = new Set(context.weakAreas.map((item) => `${item.category}::${item.subCategory}::${item.topicTag}`));

let raw = llmResponse.choices?.[0]?.message?.content ?? llmResponse.output_text ?? llmResponse.content ?? llmResponse;
if (Array.isArray(raw)) {
  raw = raw.map((item) => item?.text ?? '').join('\n');
}
if (typeof raw === 'object') {
  raw = JSON.stringify(raw);
}
if (typeof raw !== 'string') {
  throw new Error('LLM response does not contain string content');
}

const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch {
  throw new Error('LLM returned invalid JSON');
}

if (
  typeof parsed.summary !== 'string' ||
  typeof parsed.overallAssessment !== 'string' ||
  typeof parsed.nextTryoutStrategy !== 'string' ||
  !Array.isArray(parsed.recommendations)
) {
  throw new Error('Recommendation shape is invalid');
}

if (parsed.recommendations.length > 5) {
  throw new Error('Recommendation count exceeds 5');
}

const forbiddenWords = ['pasti lulus', 'jamin lulus', 'dijamin lulus', '100% lulus'];
const resultRecommendations = parsed.recommendations.map((item, index) => {
  const key = `${item.category}::${item.subCategory}::${item.topicTag}`;
  if (!weakSet.has(key)) {
    throw new Error(`Invented topicTag detected: ${key}`);
  }

  const reason = typeof item.reason === 'string' ? item.reason.trim() : '';
  const suggestedFocus = Array.isArray(item.suggestedFocus)
    ? item.suggestedFocus.filter((value) => typeof value === 'string' && value.trim().length > 0)
    : [];

  const textBlob = `${reason} ${suggestedFocus.join(' ')} ${parsed.nextTryoutStrategy}`.toLowerCase();
  if (forbiddenWords.some((word) => textBlob.includes(word))) {
    throw new Error('Recommendation contains forbidden passing guarantee language');
  }

  return {
    priority: Number(item.priority ?? index + 1),
    priorityLevel: item.priorityLevel ?? 'MEDIUM',
    category: item.category,
    subCategory: item.subCategory,
    topicTag: item.topicTag,
    reason,
    suggestedFocus,
  };
});

return [{
  json: {
    summary: parsed.summary.trim(),
    overallAssessment: parsed.overallAssessment.trim(),
    recommendations: resultRecommendations,
    nextTryoutStrategy: parsed.nextTryoutStrategy.trim()
  }
}];
